		const b01 = y * x * tA + z * sA;
		const b02 = z * x * tA - y * sA;
		const b10 = x * y * tA - z * sA;
		const b11 = y * y * tA + cA;
		const b12 = z * y * tA + x * sA;
		const b20 = x * z * tA + y * sA;
